@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";

@custom-variant dark (&:is(.dark *));

/*
 * Design system: Wellspring palette (soft off-white, sage primary, charcoal text).
 * Semantic colors live in :root / .dark as oklch. @theme inline maps them to utilities.
 */

@theme inline {
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --radius-2xl: calc(var(--radius) + 8px);
  --radius-3xl: calc(var(--radius) + 12px);
  --radius-4xl: calc(var(--radius) + 16px);
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-ring-offset-background: var(--background);
  --color-primary-hover: var(--primary-hover);
  --shadow-card: var(--shadow-card);
  --font-sans: var(--font-sans);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
}

:root {
  --radius: 0.75rem;
  /* Wellspring palette: soft off-white #FAFAF8, sage #5C7A5C, charcoal #1C1C1A */
  --background: oklch(0.985 0.003 95);
  --foreground: oklch(0.18 0.004 60);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.18 0.004 60);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.18 0.004 60);
  --primary: oklch(0.52 0.045 145);
  --primary-foreground: oklch(0.99 0 0);
  --primary-hover: oklch(0.46 0.045 145);
  --secondary: oklch(0.96 0.004 95);
  --secondary-foreground: oklch(0.18 0.004 60);
  --muted: oklch(0.95 0.004 95);
  --muted-foreground: oklch(0.5 0.006 80);
  --accent: oklch(0.94 0.012 145);
  --accent-foreground: oklch(0.32 0.04 145);
  --destructive: oklch(0.55 0.18 27);
  --destructive-foreground: oklch(0.99 0 0);
  --border: oklch(0.91 0.005 90);
  --input: oklch(0.91 0.005 90);
  --ring: oklch(0.52 0.045 145);
  --shadow-card: 0 1px 2px rgb(28 28 26 / 0.04), 0 8px 24px -12px rgb(28 28 26 / 0.08);
  --chart-1: oklch(0.646 0.222 41.116);
  --chart-2: oklch(0.6 0.118 184.704);
  --chart-3: oklch(0.398 0.07 227.392);
  --chart-4: oklch(0.828 0.189 84.429);
  --chart-5: oklch(0.769 0.188 70.08);
  --sidebar: oklch(0.984 0.003 247.858);
  --sidebar-foreground: oklch(0.129 0.042 264.695);
  --sidebar-primary: oklch(0.208 0.042 265.755);
  --sidebar-primary-foreground: oklch(0.984 0.003 247.858);
  --sidebar-accent: oklch(0.968 0.007 247.896);
  --sidebar-accent-foreground: oklch(0.208 0.042 265.755);
  --sidebar-border: oklch(0.929 0.013 255.508);
  --sidebar-ring: oklch(0.704 0.04 256.788);
}

.dark {
  --background: oklch(0.129 0.042 264.695);
  --foreground: oklch(0.984 0.003 247.858);
  --card: oklch(0.208 0.042 265.755);
  --card-foreground: oklch(0.984 0.003 247.858);
  --popover: oklch(0.208 0.042 265.755);
  --popover-foreground: oklch(0.984 0.003 247.858);
  --primary: oklch(0.929 0.013 255.508);
  --primary-foreground: oklch(0.208 0.042 265.755);
  --primary-hover: oklch(0.85 0.02 255);
  --secondary: oklch(0.279 0.041 260.031);
  --secondary-foreground: oklch(0.984 0.003 247.858);
  --muted: oklch(0.279 0.041 260.031);
  --muted-foreground: oklch(0.704 0.04 256.788);
  --accent: oklch(0.279 0.041 260.031);
  --accent-foreground: oklch(0.984 0.003 247.858);
  --destructive: oklch(0.704 0.191 22.216);
  --destructive-foreground: oklch(0.984 0.003 247.858);
  --border: oklch(1 0 0 / 10%);
  --input: oklch(1 0 0 / 15%);
  --ring: oklch(0.551 0.027 264.364);
  --chart-1: oklch(0.488 0.243 264.376);
  --chart-2: oklch(0.696 0.17 162.48);
  --chart-3: oklch(0.769 0.188 70.08);
  --chart-4: oklch(0.627 0.265 303.9);
  --chart-5: oklch(0.645 0.246 16.439);
  --sidebar: oklch(0.208 0.042 265.755);
  --sidebar-foreground: oklch(0.984 0.003 247.858);
  --sidebar-primary: oklch(0.488 0.243 264.376);
  --sidebar-primary-foreground: oklch(0.984 0.003 247.858);
  --sidebar-accent: oklch(0.279 0.041 260.031);
  --sidebar-accent-foreground: oklch(0.984 0.003 247.858);
  --sidebar-border: oklch(1 0 0 / 10%);
  --sidebar-ring: oklch(0.551 0.027 264.364);
}

@layer base {
  * {
    border-color: var(--color-border);
    @apply outline-ring/50;
  }

  html,
  body {
    font-family: var(--font-sans);
    -webkit-font-smoothing: antialiased;
    text-rendering: optimizeLegibility;
  }

  body {
    background-color: var(--color-background);
    color: var(--color-foreground);
  }
}

/* Floating-label input (auth and similar forms) */
.field {
  position: relative;
}

.field input {
  width: 100%;
  height: 3.25rem;
  padding: 1.35rem 0.95rem 0.45rem;
  background: var(--color-card);
  border: 1px solid var(--color-border);
  border-radius: 0.625rem;
  font-size: 0.95rem;
  color: var(--color-foreground);
  outline: none;
  transition:
    border-color 150ms ease,
    box-shadow 150ms ease;
}

.field input:hover {
  border-color: oklch(0.85 0.005 90);
}

.field input:focus {
  border-color: var(--color-primary);
  box-shadow: 0 0 0 3px oklch(0.52 0.045 145 / 0.15);
}

.dark .field input:hover {
  border-color: oklch(0.45 0.02 264);
}

.dark .field input:focus {
  box-shadow: 0 0 0 3px oklch(0.551 0.027 264.364 / 0.25);
}

.field input[aria-invalid="true"] {
  border-color: var(--color-destructive);
}

.field input[aria-invalid="true"]:focus {
  box-shadow: 0 0 0 3px oklch(0.55 0.18 27 / 0.2);
}

.field label {
  position: absolute;
  left: 0.95rem;
  top: 50%;
  transform: translateY(-50%);
  color: var(--color-muted-foreground);
  font-size: 0.95rem;
  pointer-events: none;
  transition: all 150ms ease;
}

.field input:focus + label,
.field input:not(:placeholder-shown) + label {
  top: 0.55rem;
  transform: translateY(0);
  font-size: 0.7rem;
  color: var(--color-primary);
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.field input[aria-invalid="true"] + label {
  color: var(--color-destructive);
}

